import React from "react";
import KitsContainer from "../../Helpers/FormContainer";
import { AutoComplete } from "@lmb/kitsconcertomobile";
import type { IAutoCompleteElement } from "@lmb/kitsconcerto-types";
import { useAutoCompleteLogic } from "../hooks/useAutoCompleteLogic";
import { useComponentDefaults } from "@lmb/kitsconcerto/Hooks";

const KitsAutoComplete = ({ ref, ...rawProps }: IAutoCompleteElement) => {
    const { mergedProps: props, themeStyle } = useComponentDefaults('AutoComplete', rawProps, 'Select');
    const {
        id,
        rightAddon,
        leftAddon,
        errors,
        invalid,
        label,
        hideError,
        disabled,
        required,
        isFloatedLabel,
        inputSize = "md",
        forceSelection,
        completeMethod,
        helperText,
        withArrow,
        placeholder,
        isMultiple,
        localProps,
        delay,
        minLength,
        selectionLimit,
        showEmptyMessage,
    } = props;

    const {
        inputValue,
        setInputValue,
        filteredList,
        search,
        handleOnChange,
        list,
        childrenKey,
        labelKey,
    } = useAutoCompleteLogic({ isMultiple, forceSelection, completeMethod, ref });

    return (
        <KitsContainer
            id={id}
            inputSize={inputSize}
            isFloatedLabel={isFloatedLabel}
            hideError={hideError}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            helperText={helperText}
            errors={errors}
            invalid={invalid}
            label={label}
        >
            <AutoComplete
                disabled={disabled}
                placeholder={placeholder}
                value={inputValue}
                forceSelection={forceSelection}
                suggestions={Array.isArray(filteredList) ? filteredList : list}
                completeMethod={search}
                dropdown={withArrow}
                multiple={isMultiple}
                field={labelKey}
                invalid={!!invalid}
                emptyMessage="No results found"
                {...(delay != null ? { delay } : {})}
                {...(minLength != null ? { minLength } : {})}
                {...(selectionLimit != null ? { selectionLimit } : {})}
                showEmptyMessage={showEmptyMessage ?? true}
                optionGroupChildren={childrenKey ?? undefined}
                optionGroupLabel={childrenKey ? labelKey : undefined}
                style={Object.keys(themeStyle).length ? themeStyle : undefined}
                onChange={(event) => {
                    setInputValue(event.value);
                    handleOnChange(event);
                }}
                onSelect={(event) => {
                    handleOnChange(
                        { originalEvent: event.originalEvent, value: event.value },
                    );
                }}
                {...(localProps ?? {})}
            />
        </KitsContainer>
    );
};

export default KitsAutoComplete;
